def slow_sort(arr, i, j):
	if i >= j:
		return
	m = (i + j) // 2
	slow_sort(arr, i, m)
	slow_sort(arr, m + 1, j)
	if arr[j] < arr[m]:
		arr[j], arr[m] = arr[m], arr[j]
	slow_sort(arr, i, j - 1)

