function slowSort(arr, i, j) {
	if (i >= j) return;
	let m = Math.floor((i + j) / 2);
	slowSort(arr, i, m);
	slowSort(arr, m + 1, j);
	if (arr[j] < arr[m]) {
		[arr[j], arr[m]] = [arr[m], arr[j]];
	}
	slowSort(arr, i, j - 1);
}

