public static void slowSort(int[] arr, int i, int j) {
	if (i >= j) return;
	int m = (i + j) / 2;
	slowSort(arr, i, m);
	slowSort(arr, m + 1, j);
	if (arr[j] < arr[m]) {
		int temp = arr[j];
		arr[j] = arr[m];
		arr[m] = temp;
	}
	slowSort(arr, i, j - 1);
}

